module RefModule(clk, rst, up_down, Q);
    input clk, rst, up_down;
    output reg [2:0] Q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst)
            Q <= 3'b000;
        else if (up_down)
            Q <= Q + 1;
        else
            Q <= Q - 1;
    end
endmodule
